use strict;
use warnings;

my @numbers = (10, 25, 3, 47, 8);
print "Dizi uzunlugu: " . scalar(@numbers) . "\n";

my @sorted_numbers = sort { $a <=> $b } @numbers;
print "Siralanmis dizi: @sorted_numbers\n";

# Eleman ekleme (push)
push @numbers, 100;
print "\n100 eklendi: @numbers\n";

# Eleman silme (pop, shift)
my $last = pop @numbers;
print "\nSon eleman silindi ($last): @numbers\n";

# Dilimleme (slicing)
print "\nDilimleme:\n";
print "Ilk 3 eleman: @numbers[0..2]\n";

my @reversed = reverse @numbers;
print "Ters cevrilmis: @reversed\n";

# Toplam ve ortalama
my $sum = 0;
$sum += $_ for @numbers;
my $avg = $sum / scalar(@numbers);

print "\nToplam: $sum\n";
printf "Ortalama: %.2f\n", $avg;

# grep ile filtreleme
my @evens = grep { $_ % 2 == 0 } @numbers;
print "\nCift sayilar: @evens\n";

# map ile donusum
my @doubled = map { $_ * 2 } @numbers;
print "2 ile carpilmis: @doubled\n";
